import{c as s,cN as a,cG as i,cb as n,c8 as t,cf as e,cT as l,ce as p,cg as h}from"./chunks/framework.BlkIsu1j.js";const d=JSON.parse('{"title":"22. 页表与虚拟内存","description":"","frontmatter":{"title":"22. 页表与虚拟内存","outline":"deep","layout":"doc","prev":{"text":"21. 异常与中断","link":"/lang/assembly/21_exceptions_interrupts"},"next":{"text":"附录 A. RV64I 基础指令速查表","link":"/lang/assembly/appendix_a_rv64i_reference"},"sidebar":true,"date":"2026-05-31T10:00:00.000Z"},"headers":[],"relativePath":"lang/assembly/22_virtual_memory.md","filePath":"lang/assembly/22_virtual_memory.md","lastUpdated":1780237621000}'),r={id:"frontmatter-title",tabindex:"-1"};const k=s({name:"lang/assembly/22_virtual_memory.md"},[["render",function(s,d,k,c,o,g){const b=a("vitepress-mermaid");return i(),n("div",null,[t("h1",r,[e(l(s.$frontmatter.title)+" ",1),d[0]||(d[0]=t("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":"Permalink to “{{ $frontmatter.title }}”"},"​",-1))]),d[1]||(d[1]=p('<p>至此，我们学会了写汇编程序、处理异常和中断、与 C 代码互操作。但所有这些操作中使用的&quot;地址&quot;——<code>la a0, label</code> 中的 <code>label</code>、<code>ld t0, 0(sp)</code> 中的 <code>0(sp)</code>——究竟是物理 RAM 中的真实地址，还是被 CPU 悄悄翻译过的虚拟地址？答案是：在有操作系统的环境中，<strong>所有地址都是虚拟地址</strong>。本章剖析 RISC-V 的虚拟内存机制：页表如何工作、TLB 如何让翻译变快、以及这一切对汇编程序员意味着什么。</p><h2 id="虚拟内存的作用" tabindex="-1">虚拟内存的作用 <a class="header-anchor" href="#虚拟内存的作用" aria-label="Permalink to “虚拟内存的作用”">​</a></h2><h3 id="三个核心目标" tabindex="-1">三个核心目标 <a class="header-anchor" href="#三个核心目标" aria-label="Permalink to “三个核心目标”">​</a></h3><p>虚拟内存并非&quot;让程序员省心&quot;的便利设施——它是现代操作系统安全性和可靠性的基石。三个核心目标：</p><p><strong>1. 隔离（Isolation）</strong></p><p>每个用户进程拥有独立的虚拟地址空间。进程 A 的 <code>0x10000</code> 和进程 B 的 <code>0x10000</code> 映射到完全不同的物理页帧。用户程序无法（也不应该）访问属于其他进程或内核的物理内存。页表是硬件强制隔离的机制——没有合法 PTE 映射，任何 load/store 都将在硬件层面触发页错误异常。</p><p><strong>方案 1：Mermaid 流程图</strong></p>',7)),h(b,{value:'flowchart LR\n    subgraph VA_A["进程 A 虚拟地址"]\n        A0x10000["0x10000"]\n        A0x11000["0x11000"]\n    end\n    subgraph VA_B["进程 B 虚拟地址"]\n        B0x10000["0x10000"]\n    end\n    subgraph PA["物理内存"]\n        direction TB\n        PA42["物理页帧 #42 (A 的数据)"]\n        PA17["物理页帧 #17 (A 的代码)"]\n        PA99["物理页帧 #99 (B 的数据)"]\n        PA3["物理页帧 #3 (B 的栈)"]\n        PA91["物理页帧 #91 (A 的栈)"]\n    end\n    A0x10000 --\x3e PA42\n    A0x11000 --\x3e PA17\n    B0x10000 --\x3e PA99'}),d[2]||(d[2]=p('<p><strong>方案 2：Markdown 表格</strong></p><table tabindex="0"><thead><tr><th>进程</th><th>虚拟地址</th><th>→</th><th>物理内存</th></tr></thead><tbody><tr><td>A</td><td><code>0x10000</code></td><td>→</td><td>物理页帧 #42（A 的数据）</td></tr><tr><td>A</td><td><code>0x11000</code></td><td>→</td><td>物理页帧 #17（A 的代码）</td></tr><tr><td>B</td><td><code>0x10000</code></td><td>→</td><td>物理页帧 #99（B 的数据）</td></tr><tr><td>—</td><td>—</td><td>→</td><td>物理页帧 #3（B 的栈）</td></tr><tr><td>—</td><td>—</td><td>→</td><td>物理页帧 #91（A 的栈）</td></tr></tbody></table><p><strong>方案 3：ASCII art（纯英文）</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Process A VA:               Physical Memory:</span></span>\n<span class="line"><span>  0x10000 ────────┐        ┌──────────────────────┐</span></span>\n<span class="line"><span>  0x11000 ──────┐  │   ┌──→│ Frame #42 (A data)    │</span></span>\n<span class="line"><span>                 │  │   │   ├──────────────────────┤</span></span>\n<span class="line"><span>                 │  └───│─→│ Frame #17 (A code)    │</span></span>\n<span class="line"><span>                 │      │   ├──────────────────────┤</span></span>\n<span class="line"><span>Process B VA:    │      │   │ Frame #99 (B data)    │</span></span>\n<span class="line"><span>  0x10000 ──────┐│      │   ├──────────────────────┤</span></span>\n<span class="line"><span>                 ││      └──→│ Frame #3  (B stack)  │</span></span>\n<span class="line"><span>                 └─────────→│ Frame #91 (A stack)   │</span></span>\n<span class="line"><span>                            └──────────────────────┘</span></span></code></pre></div><p><strong>2. 扩展（Extension）</strong></p><p>虚拟地址空间可以远大于物理内存。在 Sv39 下，每个进程有 512 GiB 的用户地址空间（64 位地址的低 256 TiB 的一半）。操作系统通过<strong>按需分页（demand paging）</strong>和<strong>交换（swapping）</strong>，让物理内存作为&quot;热数据&quot;的缓存，不活跃的页被移到磁盘。程序不需要知道当前有多少空闲 RAM——它看到的始终是那个&quot;平坦、连续&quot;的虚拟空间。</p><p><strong>3. 保护（Protection）</strong></p><p>页表项（PTE）中的 R/W/X 位允许操作系统精确控制每个页面的访问权限：</p><ul><li>代码段：R + X（可读可执行，不可写）</li><li>数据段：R + W（可读可写，不可执行）</li><li>只读常量：R（不可写不可执行）</li></ul><p>违反权限的访问被硬件截获为页错误异常——这是 W^X（Write XOR Execute）安全策略和栈溢出保护的硬件基础。</p><h2 id="satp-地址翻译的开关" tabindex="-1">satp：地址翻译的开关 <a class="header-anchor" href="#satp-地址翻译的开关" aria-label="Permalink to “satp：地址翻译的开关”">​</a></h2><h3 id="satp-csr-字段" tabindex="-1">satp CSR 字段 <a class="header-anchor" href="#satp-csr-字段" aria-label="Permalink to “satp CSR 字段”">​</a></h3><p><code>satp</code>（Supervisor Address Translation and Protection）是 S 模式下的 CSR，控制整个虚拟内存的开关和翻译方式。在 RV64 中，<code>satp</code> 的位布局如下：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>位 [63:60]  MODE:  0=Bare(无翻译), 8=Sv39, 9=Sv48, 10=Sv57</span></span>\n<span class="line"><span>位 [59:44]  ASID:  地址空间 ID（16 位，最多 65535 个地址空间）</span></span>\n<span class="line"><span>位 [43:0]   PPN:   根页表的物理页号（44 位物理地址）</span></span></code></pre></div><p>支持的翻译模式：</p><table tabindex="0"><thead><tr><th>MODE 值</th><th>名称</th><th>虚拟地址宽度</th><th>页表级数</th><th>虚拟地址空间</th></tr></thead><tbody><tr><td>0</td><td>Bare</td><td>无翻译</td><td>0</td><td>=物理地址</td></tr><tr><td>8</td><td>Sv39</td><td>39 位</td><td>3 级</td><td>512 GiB</td></tr><tr><td>9</td><td>Sv48</td><td>48 位</td><td>4 级</td><td>256 TiB</td></tr><tr><td>10</td><td>Sv57</td><td>57 位</td><td>5 级</td><td>128 PiB</td></tr></tbody></table><p>Sv39（39 位，3 级页表）是目前 RISC-V Linux 最常用的模式。Sv48 和 Sv57 是为大内存服务器和数据中心准备的——对汇编学习而言，完全掌握 Sv39 就足够理解虚拟内存的本质。</p><h3 id="bare-模式" tabindex="-1">Bare 模式 <a class="header-anchor" href="#bare-模式" aria-label="Permalink to “Bare 模式”">​</a></h3><p>当 <code>satp.MODE = 0</code>（Bare 模式），地址翻译被完全绕过——虚拟地址 = 物理地址。bare-metal 程序和 M 模式代码通常运行在 Bare 模式下。嵌入式系统如果不需要虚拟内存，根本不需要实现 satp。</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 启用 Bare 模式（关掉地址翻译）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    csrw    satp, x0            </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 写 0 到 satp: MODE=0, ASID=0, PPN=0</span></span></code></pre></div><h3 id="切换-satp-sfence-vma" tabindex="-1">切换 satp：sfence.vma <a class="header-anchor" href="#切换-satp-sfence-vma" aria-label="Permalink to “切换 satp：sfence.vma”">​</a></h3><p>写入 <code>satp</code> 不会立即影响正在执行的指令流——但下一条指令开始，所有后续取指和访存都将使用新的页表。由于 TLB 中可能缓存了旧翻译，必须在写 <code>satp</code> 后执行 TLB 刷新：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 切换到新的页表</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    la      t0, root_page_table</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    srli    t0, t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">12</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # 页表物理地址 &gt;&gt; 12 = PPN</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    li      t1, (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &lt;&lt; </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">60</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # MODE = Sv39</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    or</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      t0, t0, t1</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    csrw    satp, t0            </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 写入新的根页表</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    sfence</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.vma                  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 刷新所有 TLB 条目</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 之后的所有访存走新页表</span></span></code></pre></div><p><code>sfence.vma</code> 的完整形式允许清除特定虚拟地址或特定 ASID 的 TLB 条目。不加参数时，刷新<strong>所有 hart 上、所有 ASID、所有虚拟地址</strong>的 TLB 条目——最彻底的刷新，也是上下文切换中的标准做法。</p><h2 id="sv39-页表结构" tabindex="-1">Sv39 页表结构 <a class="header-anchor" href="#sv39-页表结构" aria-label="Permalink to “Sv39 页表结构”">​</a></h2><h3 id="虚拟地址分解" tabindex="-1">虚拟地址分解 <a class="header-anchor" href="#虚拟地址分解" aria-label="Permalink to “虚拟地址分解”">​</a></h3><p>Sv39 将 39 位虚拟地址划分为四个部分：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>虚拟地址 (39 位):</span></span>\n<span class="line"><span>┌──────────┬──────────┬──────────┬─────────────┐</span></span>\n<span class="line"><span>│  VPN[2]  │  VPN[1]  │  VPN[0]  │   offset    │</span></span>\n<span class="line"><span>│  9 bits   │  9 bits   │  9 bits   │  12 bits    │</span></span>\n<span class="line"><span>│  [38:30]  │  [29:21]  │  [20:12]  │   [11:0]    │</span></span>\n<span class="line"><span>└──────────┴──────────┴──────────┴─────────────┘</span></span>\n<span class="line"><span>     ↓           ↓           ↓           ↓</span></span>\n<span class="line"><span>  L2 页表     L1 页表     L0 页表     页内偏移</span></span>\n<span class="line"><span>  (根表)     (中间表)    (叶表)      (4KB 页面)</span></span></code></pre></div><p>每一级 VPN 是 9 位——恰好索引一张 512 个条目的页表（2^9 = 512，每条 PTE 8 字节，511 × 8 + 8 = 4096 字节 = 恰好一页）。这是页表设计中的经典&quot;自相似&quot;模式：每一级页表都恰好占一页物理内存。</p><h3 id="三级翻译流程" tabindex="-1">三级翻译流程 <a class="header-anchor" href="#三级翻译流程" aria-label="Permalink to “三级翻译流程”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>                  Virtual Address</span></span>\n<span class="line"><span>          ┌────────────────────────────┐</span></span>\n<span class="line"><span>          │ VPN[2] │ VPN[1] │ VPN[0] │ off │</span></span>\n<span class="line"><span>          └───┬────┴───┬────┴───┬────┴──┬──┘</span></span>\n<span class="line"><span>              │        │        │       │</span></span>\n<span class="line"><span>    satp.PPN ─┤        │        │       │</span></span>\n<span class="line"><span>    ┌─────────▼──┐     │        │       │</span></span>\n<span class="line"><span>    │  L2 页表    │     │        │       │</span></span>\n<span class="line"><span>    │  (根表)     │     │        │       │</span></span>\n<span class="line"><span>    │ VPN[2]→PPN  │     │        │       │</span></span>\n<span class="line"><span>    │ ┌─────────┐│     │        │       │</span></span>\n<span class="line"><span>    │ │PTE[VPN2]├┼─────▼──┐     │       │</span></span>\n<span class="line"><span>    │ └─────────┘│ │  L1 页表 │     │       │</span></span>\n<span class="line"><span>    └────────────┘ │ VPN[1]→PPN│    │       │</span></span>\n<span class="line"><span>                   │ ┌─────────┐│    │       │</span></span>\n<span class="line"><span>                   │ │PTE[VPN1]├┼────▼──┐    │</span></span>\n<span class="line"><span>                   │ └─────────┘│ │L0 页表│   │</span></span>\n<span class="line"><span>                   └────────────┘ │VPN[0]→PPN│  │</span></span>\n<span class="line"><span>                                  │┌─────────┐│  │</span></span>\n<span class="line"><span>                                  ││PTE[VPN0]├┼──▼─────┐</span></span>\n<span class="line"><span>                                  │└─────────┘││Physical│</span></span>\n<span class="line"><span>                                  └────────────┘│  Page  │</span></span>\n<span class="line"><span>                                                 │ +offset│</span></span>\n<span class="line"><span>                                                 └────────┘</span></span></code></pre></div><p>每一步：用 VPN[i]（9 位）× 8 字节 = 偏移，在当前页表基址处查找 PTE，读出 PPN + Flags。</p><h3 id="pte-格式" tabindex="-1">PTE 格式 <a class="header-anchor" href="#pte-格式" aria-label="Permalink to “PTE 格式”">​</a></h3><p>一个 PTE（Page Table Entry）长度为 64 位，分为 PPN 和 Flags 两大部分：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>位 [63:54]  保留（未来扩展）</span></span>\n<span class="line"><span>位 [53:10]  PPN[2:0] (44 位物理页号，每个 PPN 字段 26 位高 + 9 位中 + 9 位低)</span></span>\n<span class="line"><span>位 [9:0]    Flags (10 位标志)</span></span></code></pre></div><p>10 个标志位的详细定义：</p><table tabindex="0"><thead><tr><th>位</th><th>名称</th><th>描述</th></tr></thead><tbody><tr><td>0</td><td>V</td><td>Valid——该 PTE 是否有效。0=无效（访问触发页错误）</td></tr><tr><td>1</td><td>R</td><td>Readable——可读</td></tr><tr><td>2</td><td>W</td><td>Writable——可写</td></tr><tr><td>3</td><td>X</td><td>Executable——可执行</td></tr><tr><td>4</td><td>U</td><td>User——U 模式可访问。0=仅 S/M 模式可访问</td></tr><tr><td>5</td><td>G</td><td>Global——全局映射，所有 ASID 共享（如内核页）</td></tr><tr><td>6</td><td>A</td><td>Accessed——已被读过/执行过（硬件自动置位或软件模拟）</td></tr><tr><td>7</td><td>D</td><td>Dirty——已被写过（硬件自动置位或软件模拟）</td></tr><tr><td>8-9</td><td>RSW</td><td>Reserved for Supervisor Software——OS 自由使用</td></tr></tbody></table><p>R/W/X 的组合定义了标准的权限语义：</p><table tabindex="0"><thead><tr><th>R</th><th>W</th><th>X</th><th>语义</th></tr></thead><tbody><tr><td>0</td><td>0</td><td>0</td><td>非叶节点（指向下一级页表）</td></tr><tr><td>1</td><td>0</td><td>0</td><td>只读数据页</td></tr><tr><td>0</td><td>1</td><td>0</td><td><strong>保留（非法组合）</strong></td></tr><tr><td>1</td><td>1</td><td>0</td><td>可读写数据页</td></tr><tr><td>0</td><td>0</td><td>1</td><td>只执行（纯代码页）</td></tr><tr><td>1</td><td>0</td><td>1</td><td>可读可执行（典型代码段）</td></tr><tr><td>1</td><td>1</td><td>1</td><td>可读可写可执行（不推荐，W^X 违规）</td></tr></tbody></table><p>注意 <code>W=1, R=0</code> 是非法组合——可写但不可读的页面在 RISC-V 架构中没有意义。</p><h3 id="大页-superpage" tabindex="-1">大页（Superpage） <a class="header-anchor" href="#大页-superpage" aria-label="Permalink to “大页（Superpage）”">​</a></h3><p>Sv39 支持两种大页——当翻译提前终止于 L2 或 L1 层时：</p><table tabindex="0"><thead><tr><th>终止于</th><th>页面大小</th><th>虚拟地址覆盖</th></tr></thead><tbody><tr><td>L0（叶）</td><td>4 KiB</td><td>off=12 bit</td></tr><tr><td>L1（中间）</td><td>2 MiB</td><td>VPN[0]+off=21 bit（512×4KB）</td></tr><tr><td>L2（根）</td><td>1 GiB</td><td>VPN[1]+VPN[0]+off=30 bit（512×2MB）</td></tr></tbody></table><p>大页的存在是出于性能考量——TLB 条目有限，一条覆盖 2 MiB 的条目比 512 条各自覆盖 4 KiB 的条目更高效。但大页的对齐要求很高：2 MiB 大页的物理基址必须 2 MiB 对齐，1 GiB 巨页必须 1 GiB 对齐。</p><p>操作系统内核代码（如 Linux 的 <code>__vmlinux</code> 映射）和大型数据库的缓冲池是典型的大页应用场景。对汇编程序员来说，大页通常是透明的——你不会直接控制是否使用大页。</p><h2 id="tlb-地址翻译缓存" tabindex="-1">TLB：地址翻译缓存 <a class="header-anchor" href="#tlb-地址翻译缓存" aria-label="Permalink to “TLB：地址翻译缓存”">​</a></h2><h3 id="为什么需要-tlb" tabindex="-1">为什么需要 TLB <a class="header-anchor" href="#为什么需要-tlb" aria-label="Permalink to “为什么需要 TLB”">​</a></h3><p>走完一次完整的三级页表翻译需要访存 3 次（读 L2 → 读 L1 → 读 L0），再加上目标数据的访问，一共 4 次内存操作——这是不可接受的性能损失。TLB（Translation Lookaside Buffer）是在 MMU 内部的硬件缓存，缓存最近使用的 VA→PA 翻译。</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>没有 TLB 缓存时：</span></span>\n<span class="line"><span>  ld t0, 0(a0)</span></span>\n<span class="line"><span>  → 读 L2 PTE（内存访问 1）</span></span>\n<span class="line"><span>  → 读 L1 PTE（内存访问 2）</span></span>\n<span class="line"><span>  → 读 L0 PTE（内存访问 3）</span></span>\n<span class="line"><span>  → 读目标数据（内存访问 4）</span></span>\n<span class="line"><span>  总延迟：4 × 内存延迟 ≈ 200-400 个周期</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>有 TLB 命中时：</span></span>\n<span class="line"><span>  ld t0, 0(a0)</span></span>\n<span class="line"><span>  → TLB 命中 → 直接得到 PA</span></span>\n<span class="line"><span>  → 读目标数据（内存访问 1）</span></span>\n<span class="line"><span>  总延迟：1 × 内存延迟 ≈ 50-100 个周期</span></span></code></pre></div><p>实际程序中 TLB 命中率通常 &gt; 99%——因为内存访问具有极强的时空局部性（相邻的指令和数据页被反复访问）。即使是 32 条 TLB 条目的小容量，对大多数程序也能维持 &gt; 95% 的命中率。</p><h3 id="sfence-vma-tlb-维护指令" tabindex="-1">sfence.vma：TLB 维护指令 <a class="header-anchor" href="#sfence-vma-tlb-维护指令" aria-label="Permalink to “sfence.vma：TLB 维护指令”">​</a></h3><p>TLB 是硬件缓存，不会自动感知页表的修改。当软件修改页表（添加/删除映射、修改权限）后，必须显式刷新相关的 TLB 条目：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">sfence</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.vma x0, x0             </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 刷新当前 hart 的所有 TLB 条目</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">sfence</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.vma a0, x0             </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 刷新虚拟地址 a0 对应的 TLB 条目</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">sfence</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.vma x0, a1             </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 刷新 ASID=a1 的所有 TLB 条目</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">sfence</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.vma a0, a1             </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 刷新指定地址+指定 ASID 的 TLB 条目</span></span></code></pre></div><p>常见使用场景：</p><ol><li><strong>进程切换</strong>：切换 <code>satp.ASID</code> 并执行 <code>sfence.vma</code></li><li><strong>页表修改</strong>：<code>munmap</code> 后刷新被释放范围的 TLB</li><li><strong>mprotect</strong>：修改页面权限后刷新 TLB（否则旧权限可能残留在缓存中）</li></ol><h3 id="asid-避免全量-tlb-刷新" tabindex="-1">ASID：避免全量 TLB 刷新 <a class="header-anchor" href="#asid-避免全量-tlb-刷新" aria-label="Permalink to “ASID：避免全量 TLB 刷新”">​</a></h3><p>如果不使用 ASID，每次进程切换都要用 <code>sfence.vma</code> 清空整个 TLB——新进程的代码和数据会被全部冷启动，性能代价显著。ASID（Address Space ID）为每个进程分配一个唯一标识，TLB 条目标记所属 ASID，这样进程 A 和进程 B 的翻译可以同时存在于 TLB 中。</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 进程切换时：只需切换 ASID，不需要 sfence.vma</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    li      t0, (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &lt;&lt; </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">60</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # MODE = Sv39</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    or</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      t0, t0, a0         </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # a0 = 新进程的 ASID（移位到 [59:44]）</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    or</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      t0, t0, a1         </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # a1 = 新进程的根页表 PPN</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    csrw    satp, t0</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 不执行 sfence.vma——TLB 中的旧 ASID 条目不会与新 ASID 匹配</span></span></code></pre></div><p>16 位 ASID 支持最多 65535 个并发地址空间。实际 Linux 中 ASID 的分配更加复杂——当 ASID 耗尽时需要回收（刷掉原本持有者），但框架本身已足够容纳绝大多数场景。</p><h2 id="对汇编程序员的意义" tabindex="-1">对汇编程序员的意义 <a class="header-anchor" href="#对汇编程序员的意义" aria-label="Permalink to “对汇编程序员的意义”">​</a></h2><h3 id="你看到的总是虚拟地址" tabindex="-1">你看到的总是虚拟地址 <a class="header-anchor" href="#你看到的总是虚拟地址" aria-label="Permalink to “你看到的总是虚拟地址”">​</a></h3><p>在所有用户态汇编程序中，<code>la</code>、<code>ld</code>、<code>sd</code>、<code>j</code> 使用的地址<strong>全部是虚拟地址</strong>。CPU 的 MMU 在每条访存指令背后默默地将它们翻译为物理地址。你不需要手动参与翻译过程。</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    la      a0, buffer          </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # a0 = 虚拟地址（不是物理地址）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ld      t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(a0)           </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 访问的是虚拟地址，MMU 翻译到物理 RAM</span></span></code></pre></div><h3 id="页错误是-正常-异常" tabindex="-1">页错误是&quot;正常&quot;异常 <a class="header-anchor" href="#页错误是-正常-异常" aria-label="Permalink to “页错误是&quot;正常&quot;异常”">​</a></h3><p>当你尝试访问一个&quot;合法但尚未映射&quot;的虚拟地址时，CPU 触发页错误异常（<code>mcause=12/13/15</code>）。这不是 bug——它是虚拟内存正常运作的一部分。</p><p>经典的惰性分配（Lazy Allocation）场景：</p><div class="language-c"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// C 代码</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">int</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">p </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> malloc</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1024</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1024</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // 返回虚拟地址，未分配物理页</span></span>\n<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">p</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 42</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                     // 第一次访问 → 触发页错误</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                                // OS 分配物理页 → 建立 PTE → 返回重试</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                                // 第二次访问 → TLB 命中 → 直接写入</span></span></code></pre></div><p>从汇编视角看，<code>malloc</code> 之后的 <code>sd t0, 0(a0)</code> 可能触发一次无形的页错误处理——你的代码看起来是&quot;一次写入&quot;，实际上 OS 和硬件协作完成了&quot;缺页 → 分配 → 映射 → 重试&quot;的过程。</p><h3 id="连续虚拟地址不等于连续物理地址" tabindex="-1">连续虚拟地址不等于连续物理地址 <a class="header-anchor" href="#连续虚拟地址不等于连续物理地址" aria-label="Permalink to “连续虚拟地址不等于连续物理地址”">​</a></h3><p>这是理解虚拟内存后最重要的直观改变：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 用户态程序视角：两块&quot;相邻&quot;的数据</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    la      a0, array_a         </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # a0 = 0x10000</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    la      a1, array_b         </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # a1 = 0x11000  （看起来&quot;挨着&quot;）</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 但在物理内存中，array_a 可能在物理页帧 #42，</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # array_b 可能在物理页帧 #781——完全不相邻</span></span></code></pre></div><p>物理内存的碎片化和离散分配被页表&quot;拼接&quot;成用户程序眼中连续平坦的地址空间。</p><h3 id="对性能调优的实际影响" tabindex="-1">对性能调优的实际影响 <a class="header-anchor" href="#对性能调优的实际影响" aria-label="Permalink to “对性能调优的实际影响”">​</a></h3><p>理解虚拟内存在以下场景中有直接好处：</p><ol><li><strong>避免跨页访问</strong>：频繁跨越 4 KiB 边界的访存模式会加倍 TLB 压力</li><li><strong>理解 TLB 抖动</strong>：访问模式过于分散（超过 TLB 容量）会导致频繁的页表遍历——<code>perf stat -e dtlb_load_misses</code> 可以观测</li><li><strong>大页的价值</strong>：处理超大数组时，使用 2 MiB 大页可将 TLB 覆盖范围扩大 512 倍</li><li><strong>理解 <code>wfi</code> 的行为</strong>：在虚拟内存使能的环境中，<code>wfi</code> 可能因等待 TLB shootdown（其他 hart 发起的 <code>sfence.vma</code> 广播）而延迟醒来</li></ol><h2 id="构建一个最小页表-概念示例" tabindex="-1">构建一个最小页表（概念示例） <a class="header-anchor" href="#构建一个最小页表-概念示例" aria-label="Permalink to “构建一个最小页表（概念示例）”">​</a></h2><p>以下示例展示如何在 Bare 模式下为 M 模式 bare-metal 程序构建一个 Sv39 页表。这不是通常的操作方式（M 模式一般直接用 Bare），但能直观展示页表的结构：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    .</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">section .data</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    .align </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">12</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                    # 4 KiB 对齐</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">root_page_table:</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # L2 页表：只有一个条目，映射 VPN[2]=0 到下一级</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    .</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">dword</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (l1_page_table &gt;&gt; </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) | </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0x01</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # PPN | V=1, R/W/X=0(非叶)</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    .align </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">12</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">l1_page_table:</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # L1 页表：映射 VPN[1]=0 到下一级（最终为 4KB 页面）</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 这里使用 2 MiB 大页直接映射</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    .</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">dword</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0x80000000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &gt;&gt; </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) | </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0x0F</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # PPN | V=1, R=1, W=1, X=1</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 其余 511 个条目全部为 0（无效）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    .fill </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">511</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 启用这个页表（M 模式需先切换到 S 模式或通过特殊配置）</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 注意：此例仅为概念演示，实际在 U/S 模式下使用</span></span></code></pre></div><p>实际上物理地址 &gt;&gt; 12 才得到 PPN，PTE 中的 PPN 是物理地址的高位部分（&gt;&gt; 2 是因为 PTE 中 PPN 从 bit 10 开始）。这里的 <code>&gt;&gt; 2</code> 是简化——真实代码中需要精确定位 PPN 在 PTE 中的位置。</p><h2 id="本章要点" tabindex="-1">本章要点 <a class="header-anchor" href="#本章要点" aria-label="Permalink to “本章要点”">​</a></h2><ul><li>虚拟内存通过页表实现 VA→PA 翻译，提供隔离（独立地址空间）、扩展（按需分页）和保护（R/W/X 权限）三大能力</li><li>Sv39 是 RISC-V Linux 的主流页表格式：39 位 VA 经三级页表（L2→L1→L0）翻译，支持 4 KiB / 2 MiB / 1 GiB 三种页面大小</li><li><code>satp</code> CSR 控制翻译的开关（MODE）和根页表的物理位置（PPN）；写入 <code>satp</code> 后必须执行 <code>sfence.vma</code> 刷新 TLB</li><li>TLB 缓存 VA→PA 翻译，命中率 &gt;99%，是虚拟内存体系实用化的关键——<code>sfence.vma</code> 维护 TLB 一致性，ASID 避免进程切换时全量刷新</li><li>对汇编程序员而言，地址翻译是透明的——但你应理解&quot;连续虚拟地址不等于连续物理地址&quot;，以及页错误作为正常异常在惰性分配中的作用</li></ul>',81))])}]]);export{d as __pageData,k as default};
